// Simulate scanning Azure for unused resources
// In production: call Azure Resource Graph REST API
// GET https://management.azure.com/providers/Microsoft.ResourceGraph/resources

const unusedResources = [
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-prod/providers/Microsoft.Compute/disks/old-disk-01',
    name: 'old-disk-01',
    type: 'Managed Disk',
    sizeGB: 128,
    monthlyCostUSD: 8.19,
    lastUsed: '2024-09-12',
    reason: 'Unattached for 60+ days'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-prod/providers/Microsoft.Compute/disks/backup-disk-old',
    name: 'backup-disk-old',
    type: 'Managed Disk',
    sizeGB: 256,
    monthlyCostUSD: 16.38,
    lastUsed: '2024-08-01',
    reason: 'Unattached for 90+ days'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-prod/providers/Microsoft.Compute/disks/test-disk-feb',
    name: 'test-disk-feb',
    type: 'Managed Disk',
    sizeGB: 64,
    monthlyCostUSD: 4.10,
    lastUsed: '2024-02-14',
    reason: 'Test disk, never attached to VM'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-prod/providers/Microsoft.Compute/snapshots/snap-2024-06',
    name: 'snap-2024-06',
    type: 'Snapshot',
    sizeGB: 512,
    monthlyCostUSD: 18.43,
    lastUsed: '2024-06-15',
    reason: 'Snapshot older than 90 days'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-prod/providers/Microsoft.Compute/snapshots/snap-2024-07',
    name: 'snap-2024-07',
    type: 'Snapshot',
    sizeGB: 512,
    monthlyCostUSD: 18.43,
    lastUsed: '2024-07-01',
    reason: 'Snapshot older than 90 days'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-dev/providers/Microsoft.Compute/snapshots/dev-snap-old',
    name: 'dev-snap-old',
    type: 'Snapshot',
    sizeGB: 256,
    monthlyCostUSD: 9.22,
    lastUsed: '2024-05-20',
    reason: 'Dev environment snapshot, stale'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-prod/providers/Microsoft.Network/publicIPAddresses/unused-ip-01',
    name: 'unused-ip-01',
    type: 'Public IP',
    sizeGB: 0,
    monthlyCostUSD: 3.65,
    lastUsed: '2024-10-01',
    reason: 'Not associated with any resource'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-prod/providers/Microsoft.Network/publicIPAddresses/unused-ip-02',
    name: 'unused-ip-02',
    type: 'Public IP',
    sizeGB: 0,
    monthlyCostUSD: 3.65,
    lastUsed: '2024-09-15',
    reason: 'Not associated with any resource'
  },
  {
    id: '/subscriptions/xxx/resourceGroups/waresmedia-dev/providers/Microsoft.Storage/storageAccounts/devteststore2023',
    name: 'devteststore2023',
    type: 'Storage Account',
    sizeGB: 50,
    monthlyCostUSD: 1.02,
    lastUsed: '2023-12-01',
    reason: 'No activity in 6+ months'
  }
];

const totalCost = unusedResources.reduce((sum, r) => sum + r.monthlyCostUSD, 0).toFixed(2);

return [{
  json: {
    scanTimestamp: new Date().toISOString(),
    unusedResources,
    totalCount: unusedResources.length,
    totalMonthlyCostUSD: parseFloat(totalCost),
    deleteAfter: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString()
  }
}];

const data = $input.first().json;

// Format a clean report
const lines = data.unusedResources.map(r =>
  `  • ${r.name} (${r.type}) — $${r.monthlyCostUSD}/mo — ${r.reason}`
).join('\n');

const report = {
  agentId: 'nightly-cleanup',
  agentName: 'Nightly Cleanup Agent',
  timestamp: data.scanTimestamp,
  resources: data.unusedResources,
  totalCount: data.totalCount,
  totalMonthlyCostUSD: data.totalMonthlyCostUSD,
  deleteAfter: data.deleteAfter,
  status: 'pending_deletion',
  slackMessage: `🧹 *Nightly Cleanup Report* | ${new Date().toDateString()}\n> Found *${data.totalCount} unused resources* totalling *$${data.totalMonthlyCostUSD}/month*\n\n${lines}\n\n> ⏰ Will auto-delete in *24 hours* unless you reply SKIP or approve on the dashboard.`
};

return [{ json: report }];

// In production: fetch yesterday's cleanup blob and check if SKIP was sent
// For demo: simulate auto-deletion

const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().split('T')[0];

// Simulate: no SKIP received, proceed with deletion
const deletedResources = [
  { name: 'old-disk-01', type: 'Managed Disk', savedPerMonth: 8.19 },
  { name: 'backup-disk-old', type: 'Managed Disk', savedPerMonth: 16.38 },
  { name: 'snap-2024-06', type: 'Snapshot', savedPerMonth: 18.43 },
  { name: 'unused-ip-01', type: 'Public IP', savedPerMonth: 3.65 }
];

const totalSaved = deletedResources.reduce((s, r) => s + r.savedPerMonth, 0).toFixed(2);

return [{
  json: {
    deletedAt: new Date().toISOString(),
    deletedResources,
    totalDeleted: deletedResources.length,
    monthlySavings: parseFloat(totalSaved),
    slackMessage: `✅ *Cleanup complete* | Deleted ${deletedResources.length} resources\n> Monthly savings: *$${totalSaved}*\n> Resources: ${deletedResources.map(r => r.name).join(', ')}`
  }
}];
